INSERT INTO `nuancier_facades` (`id`, `category_id`, `title`, `content`, `slug`, `priority`, `deleted_at`, `created_at`, `updated_at`) VALUES
('0c410272-1e1b-4548-88b1-965c169ebde9', 1, 'LUXE-CASHMER', '<span style=\"color: rgb(43, 43, 43); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 17px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 500; letter-spacing: normal; orphans: 2; text-align: left; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; display: inline !important; float: none;\">Le caractère neutre et intemporel Cashmer est une couleur chaude avec beaucoup de personnalité qui se marie bien avec le bois et d’autres nuances de gris ou de blanc. La finition Zénit souligne son caractère neutre et intemporel et la brillance de la technologie Luxe apporte un supplément de lumière à la pièce.</span>', 'luxe-cashmer', 5, NULL, '2025-04-09 11:16:54', '2025-04-09 16:35:08'),
('193e86d9-6d65-49e9-96be-794957997e6d', 2, 'ZENIT-NEGRO SUPERMAT', NULL, 'zenit-negro-supermat', 9, NULL, '2025-04-09 11:18:29', '2025-04-09 16:35:40'),
('1f55853c-5805-4f69-8647-a4f1abd81d17', 5, 'STORM NEGRO NATURAL', '<span style=\"color: rgb(43, 43, 43); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 17px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; text-align: left; text-indent: 0px; text-transform: none; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; display: inline !important; float: none;\">Inspirée par la force et la beauté de la pierre, est un classique revisité en noir ou en gris, avec de fines veines blanches. Sa surface forte évoque le côté plus dynamique de la nature, tout en permettant la création de décors reposants dans le cas du modèle gris, tandis que le modèle noir donne aux surfaces un air audacieux et frappant.</span>', 'storm-negro-natural', 18, NULL, '2025-04-09 16:17:10', '2025-04-09 16:37:47'),
('246c963d-4628-4647-9f17-3d679653b07e', 1, 'LUXE-PLUS-ANTRACITA', NULL, 'luxe-plus-antracita', 6, NULL, '2025-04-09 11:17:22', '2025-04-09 16:35:15'),
('277c6d0d-5237-4822-9ab0-4e49ae8502d9', 3, 'SYNCRON-LAKELAND', '<span style=\"color: rgb(43, 43, 43); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 17px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 500; letter-spacing: normal; orphans: 2; text-align: left; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; display: inline !important; float: none;\">SYNCRON Surface texturée dans laquelle le design et la finition se complètent pour obtenir des surfaces hautement naturelles au niveau décoratif élevé.</span>', 'syncron-lakeland', 11, NULL, '2025-04-09 11:19:15', '2025-04-09 16:35:57'),
('2b7bcfe0-5fe3-4635-938d-4df6cf1e1b65', 1, 'LUXE-BURDEOS', '<span style=\"color: rgb(43, 43, 43); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 17px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 500; letter-spacing: normal; orphans: 2; text-align: left; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; display: inline !important; float: none;\">Burdeos Sophistication et chaleur dans un ton idyllique qui apporte de la couleur dans la maison.</span>', 'luxe-burdeos', 3, NULL, '2025-04-09 11:16:08', '2025-04-09 16:34:53'),
('300b3a3c-675a-42ed-bf6a-8d376b91390b', 2, 'ZENIT-INDIGO SUPERMAT', NULL, 'zenit-indigo-supermat', 7, NULL, '2025-04-09 11:17:56', '2025-04-09 16:35:22'),
('3d05dc25-5500-4814-94d8-e957fcf9f442', 3, 'SYNCRON-ANV-02-OAK', '<span style=\"color: rgb(43, 43, 43); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-size: 17px; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 500; letter-spacing: normal; orphans: 2; text-align: left; text-indent: 0px; text-transform: none; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; background-color: rgb(255, 255, 255); text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; display: inline !important; float: none;\">Anniversary Oak 02 Le caractère naturel et la beauté de la finition Registro. Il apporte une touche de chaleur, de confort et de bien-être à la décoration d’intérieur.</span>', 'syncron-anv-02-oak', 10, NULL, '2025-04-09 11:18:54', '2025-04-09 16:35:51'),
('3eb9cc63-03ed-4e10-9b1b-be65d9df1e68', 4, 'BLANCO-GRIS NATURAL', '<span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; outline: 0px; font-size: 17px; vertical-align: baseline; background: rgb(255, 255, 255); color: rgb(43, 43, 43); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; text-align: left; text-indent: 0px; text-transform: none; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Surface s’inspirant des marbres classiques de grande valeur sur lesquels les veinures subtiles sont dessinées avec élégance sur un fond blanc à l’état le plus pur.</span>', 'blanco-gris-natural', 13, NULL, '2025-04-09 16:13:47', '2025-04-09 16:37:13'),
