('80d6063e-1790-417c-b085-b0822c15ae6e', 4, 'VINT GRIS NATURAL', '<span style=\"box-sizing: border-box; margin: 0px; padding: 0px; border: 0px; outline: 0px; font-size: 17px; vertical-align: baseline; background: rgb(255, 255, 255); color: rgb(43, 43, 43); font-family: &quot;Open Sans&quot;, Arial, sans-serif; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; letter-spacing: normal; text-align: left; text-indent: 0px; text-transform: none; word-spacing: 0px; -webkit-text-stroke-width: 0px; white-space: normal; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial;\">Mélange de sable, pierre et eau, Vint symbolise la sérénité dans des tons chauds, un mouvement constant vers l’infini dans lequel le design et la technologie se conjuguent pour que tout soit possible.</span>', 'vint-gris-natural', 12, NULL, '2025-04-09 16:13:18', '2025-04-09 16:37:00'),
